static constexpr uint32_t UB_BUDGET_BYTES = 192 * 1024;
static constexpr uint32_t ALIGN_ELEMS = 64;

static ge::graphStatus TilingFunc(gert::TilingContext *context)
{
    SqueezeNetFireModuleCustomTilingData tiling;

    // Get input shapes (return type is const gert::Shape*)
    const gert::Shape *x_shape = context->GetInputShape(0);
    uint32_t N = static_cast<uint32_t>(x_shape->GetOriginShape().GetDim(0));
    uint32_t C = static_cast<uint32_t>(x_shape->GetOriginShape().GetDim(1));
    uint32_t H = static_cast<uint32_t>(x_shape->GetOriginShape().GetDim(2));
    uint32_t W = static_cast<uint32_t>(x_shape->GetOriginShape().GetDim(3));

    const gert::Shape *w_squeeze_shape = context->GetInputShape(1);
    uint32_t C_squeeze = static_cast<uint32_t>(w_squeeze_shape->GetOriginShape().GetDim(0));

    const gert::Shape *w_expand1_shape = context->GetInputShape(3);
    uint32_t C_expand1 = static_cast<uint32_t>(w_expand1_shape->GetOriginShape().GetDim(0));

    const gert::Shape *w_expand3_shape = context->GetInputShape(5);
    uint32_t C_expand3 = static_cast<uint32_t>(w_expand3_shape->GetOriginShape().GetDim(0));

    uint32_t C_expand = C_expand1 + C_expand3;
    uint32_t totalLength = N * C_expand * H * W;

    // Estimate tile size based on UB budget
    uint32_t maxTileFloats = (UB_BUDGET_BYTES / sizeof(float)) / (2 * C_squeeze + 9);
    uint32_t tileSize = (maxTileFloats > 1024) ? 1024 : maxTileFloats;
    tileSize = (tileSize / ALIGN_ELEMS) * ALIGN_ELEMS;
    if (tileSize == 0) tileSize = ALIGN_ELEMS;
    if (tileSize > N * H * W) tileSize = N * H * W;

    uint32_t numTiles = (N * H * W + tileSize - 1) / tileSize;
    uint32_t blockDim = numTiles;
    if (blockDim < 8) blockDim = 8;
    if (blockDim > 24) blockDim = 24;

    tiling.set_N(N);
    tiling.set_C(C);
    tiling.set_H(H);
    tiling.set_W(W);
    tiling.set_C_squeeze(C_squeeze);
    tiling.set_C_expand1(C_expand1);
    tiling.set_C_expand3(C_expand3);
    tiling.set_C_expand(C_expand);
    tiling.set_totalLength(totalLength);
    tiling.set_tileSize(tileSize);
    tiling.set_blockDim(blockDim);

    context->SetBlockDim(blockDim);
    tiling.SaveToBuffer(context->GetRawTilingData()->GetData(),
                        context->GetRawTilingData()->GetCapacity());
    context->GetRawTilingData()->SetDataSize(tiling.GetDataSize());

    size_t *currentWorkspace = context->GetWorkspaceSizes(1);
    currentWorkspace[0] = 0;
    return ge::GRAPH_SUCCESS;
}

